{
  "lean_declaration": "/-- Alternative coefficient formula for the composition of formal power series (Definition 7.3.1).\nFor any fixed n, the sum ∑_{d∈ℕ} fₐ · [xⁿ](g^d) is actually finite, since [xⁿ](g^d) = 0 for d > n when g has constant term 0.\nThis gives a finite sum representation of the coefficient. -/\ntheorem fps_comp_coeff_eq_finset_sum (f g : K⟦X⟧) (hg : constantCoeff g = 0) (n : ℕ) :\n    coeff n (PowerSeries.subst g f) = ∑ d in Finset.range (n+1), coeff d f * coeff n (g ^ d) := by\n  rw [fps_comp_coeff f g hg n]\n  apply finsum_eq_finset_sum (fun d ↦ coeff d f * coeff n (g ^ d)) (Finset.range (n+1))\n  intro d hd\n  rw [Finset.mem_range, not_lt] at hd\n  have h_lt : n < d := by omega\n  have hcoeff : coeff n (g ^ d) = 0 := fps_subs_wd_firstCoeffs g hg d n h_lt\n  rw [hcoeff, mul_zero]",
  "declaration_name": "fps_comp_coeff_eq_finset_sum",
  "used_context": [
    "fps_comp_coeff",
    "fps_subs_wd_firstCoeffs",
    "finsum_eq_finset_sum",
    "omega"
  ],
  "notes": [
    "Uses omega for the simple arithmetic inequality, which is available via the global Mathlib import."
  ]
}
